      .llama-head {
        animation: headNod 0.6s infinite ease-in-out alternate;
        transform-origin: 200px 100px;
      }
      @keyframes headNod {
        0% { transform: rotate(0deg) translateY(0px); }
        100% { transform: rotate(-5deg) translateY(-5px); }
      }

      .leg-left {
        animation: legKickLeft 0.6s infinite ease-in-out alternate;
        transform-origin: 170px 260px;
      }
      @keyframes legKickLeft {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(-20deg); }
      }

      .leg-right {
        animation: legKickRight 0.6s infinite ease-in-out alternate;
        transform-origin: 230px 260px;
      }
      @keyframes legKickRight {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(20deg); }
      }

      .arm-left {
        animation: armWaveLeft 0.6s infinite ease-in-out alternate;
        transform-origin: 160px 160px;
      }
      @keyframes armWaveLeft {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(-40deg); }
      }

      .arm-right {
        animation: armWaveRight 0.6s infinite ease-in-out alternate;
        transform-origin: 240px 160px;
      }
      @keyframes armWaveRight {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(40deg); }
      }

      .tail {
        animation: tailWag 0.3s infinite ease-in-out alternate;
        transform-origin: 240px 220px;
      }
      @keyframes tailWag {
        0% { transform: rotate(-10deg); }
        100% { transform: rotate(10deg); }
      }

      .disco-ball {
        animation: spin 4s infinite linear;
        transform-origin: 200px 0px;
      }
      @keyframes spin {
        0% { transform: rotateY(0deg); }
        100% { transform: rotateY(360deg); }
      }

