      }

      .beam {
        animation: beamRotate 4s infinite alternate ease-in-out;
        transform-origin: 200px 20px;
      }
      @keyframes beamRotate {
        0% { transform: rotate(-15deg); }
        100% { transform: rotate(15deg); }
      }
